import React, { useEffect, useState } from "react";
import "./App.css";
// react-icons에서 필요한 아이콘 가져오기
import { FaPlus, FaList, FaUserCircle } from "react-icons/fa";

// React Router import
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
// 페이지 컴포넌트 import
import AddTask from "./pages/AddTask";
import TaskList from "./pages/TaskList";
import MyPage from "./pages/MyPage";
import Register from "./pages/Register";
import Login from "./pages/Login";
import PrivateRoute from "./components/PrivateRoute";

function App() {
  const [tasks, setTasks] = useState([]);

  // API 요청: 일정 데이터를 가져오기
  useEffect(() => {
    const fetchTasks = async () => {
      try {
        const response = await fetch("http://localhost:5000/api/tasks", {
          headers: { Authorization: `Bearer ${localStorage.getItem("token")}` },
        });
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        console.log("Fetched tasks:", data); // 데이터 형식 확인
        setTasks(Array.isArray(data) ? data : []);
      } catch (err) {
        console.error("Failed to fetch tasks:", err.message);
        setTasks([]); // 에러 시 빈 배열 설정
      }
    };

    fetchTasks();
  }, []);


  // 좌표 계산 함수: 중요도와 긴급도 기반으로 좌표를 계산
  const calculatePosition = (task) => {
    const x = task.urgency; // 긴급도: X축
    const y = 11 - task.importance; // 중요도: Y축 (위로 높아짐)
    return { x, y };
  };

  return (
    <Router>
      {/* 라우팅에 따라 렌더링할 컴포넌트 */}
      <Routes>
        {/* 메인 페이지 */}
        <Route
          path="/"
          element={
            <div className="main-container">
              <div className="arrow up"></div>
              <div className="arrow right"></div>

              {/* Header Section with Buttons */}
              <div className="header">
                <Link to="/add-task">
                  <button className="header-button">
                    <FaPlus size={20} />
                  </button>
                </Link>
                <Link to="/task-list">
                  <button className="header-button">
                    <FaList size={20} />
                  </button>
                </Link>
                <Link to="/my-page">
                  <button className="header-button">
                    <FaUserCircle size={20} />
                  </button>
                </Link>
              </div>

              {/* Grid for Tasks */}
              <div className="grid-container">
                {tasks.map((task, index) => {
                  const { x, y } = calculatePosition(task);
                  return (
                    <button
                      key={index}
                      className="task-button"
                      style={{
                        gridColumn: x,
                        gridRow: y,
                      }}
                      onClick={() => alert(`Task: ${task.name}`)}
                    >
                      {task.name}
                    </button>
                  );
                })}
              </div>

              {/* Quadrant Layout (Background Colors) */}
              <div className="quadrant-container">
                <div className="quadrant top-left"></div>
                <div className="quadrant top-right"></div>
                <div className="quadrant bottom-left"></div>
                <div className="quadrant bottom-right"></div>
              </div>
            </div>
          }
        />

        {/* 페이지 라우트 */}
        <Route path="/add-task" element={<AddTask />} />
        <Route path="/task-list" element={<TaskList />} />
        <Route
          path="/my-page"
          element={
            <PrivateRoute>
              <MyPage />
            </PrivateRoute>
          }
        />
        <Route path="/register" element={<Register />} />
        <Route path="/login" element={<Login />} />
        <Route path="*" element={<div>404 Not Found</div>} />
      </Routes>
    </Router>
  );
}

export default App;
